/*
 * floorf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly floorf  (test_floorf_opt.elf)
 *   2. Linked with toolchain's default floorf        (test_floorf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static volatile float g_acc = 0.0f;

static void emit(float x)
{
#ifdef EN_PERF
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += floorf(vx);
#else
    float r = floorf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
#endif
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* smallest positive normal: 2^-126 = 0x00800000 */
    emit(-FLT_MIN);               /* smallest negative normal */
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit(FLT_MAX);                /* largest positive normal: 0x7f7fffff */
    emit(-FLT_MAX);               /* largest negative normal */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);           /* 1.0 exactly */
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);          /* -1.0 exactly */
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Positive integer and half-integer boundaries (14) --- */
    /* floor(n + 0.5) = n, floor(n - 0.5) = n-1 */
    emit(0.5f);    /* floor = 0 */
    emit(1.5f);    /* floor = 1 */
    emit(2.5f);    /* floor = 2 */
    emit(3.5f);    /* floor = 3 */
    emit(4.5f);    /* floor = 4 */
    emit(5.5f);    /* floor = 5 */
    emit(6.5f);    /* floor = 6 */
    emit(0.9999f); /* floor = 0 */
    emit(1.0001f); /* floor = 1 */
    emit(1.9999f); /* floor = 1 */
    emit(2.0001f); /* floor = 2 */
    emit(7.0f);    /* floor = 7 (exact integer) */
    emit(8.0f);    /* floor = 8 (exact integer) */
    emit(9.0f);    /* floor = 9 (exact integer) */

    /* --- Section 6: Negative integer and half-integer boundaries (14) --- */
    emit(-0.5f);    /* floor = -1 */
    emit(-1.5f);    /* floor = -2 */
    emit(-2.5f);    /* floor = -3 */
    emit(-3.5f);    /* floor = -4 */
    emit(-4.5f);    /* floor = -5 */
    emit(-5.5f);    /* floor = -6 */
    emit(-6.5f);    /* floor = -7 */
    emit(-0.9999f); /* floor = -1 */
    emit(-1.0001f); /* floor = -2 */
    emit(-1.9999f); /* floor = -2 */
    emit(-2.0001f); /* floor = -3 */
    emit(-7.0f);    /* floor = -7 (exact integer) */
    emit(-8.0f);    /* floor = -8 (exact integer) */
    emit(-9.0f);    /* floor = -9 (exact integer) */

    /* --- Section 7: Fractional parts across (0,1) (8) --- */
    emit(0.125f);  /* 1/8 */
    emit(0.25f);   /* 1/4 */
    emit(0.375f);  /* 3/8 */
    emit(0.625f);  /* 5/8 */
    emit(0.75f);   /* 3/4 */
    emit(0.875f);  /* 7/8 */
    emit(-0.125f); /* floor = -1 */
    emit(-0.875f); /* floor = -1 */

    /* --- Section 8: Power-of-2 exponent switching (8) --- */
    emit(2.0f);    /* 2^1 exact */
    emit(4.0f);    /* 2^2 exact */
    emit(8.0f);    /* 2^3 exact; duplicated intentionally for exponent boundary */
    emit_u(0x40000001u);  /* one ULP above 2.0 */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit_u(0x40800001u);  /* one ULP above 4.0 */
    emit_u(0x407fffffu);  /* one ULP below 4.0 */
    emit(0.5f);   /* 2^-1, already in Section 5 but critical exponent boundary */

    /* --- Section 9: Large values near float integer-precision boundary (16) --- */
    /* floorf loses fractional bits once exponent >= 23: 2^23 = 8388608 */
    emit(1.0e7f);                /* 10^7, well above 2^23: no fractional part */
    emit(-1.0e7f);
    emit(1.0e10f);               /* 10^10: floor is identity */
    emit(-1.0e10f);
    emit_u(0x4b000000u);         /* 2^23 = 8388608.0: smallest integer where mantissa is saturated */
    emit_u(0xcb000000u);         /* -2^23 */
    emit_u(0x4b000001u);         /* 2^23 + 1 ULP */
    emit_u(0xcb000001u);         /* -(2^23 + 1 ULP) */
    emit_u(0x4affffffu);         /* one ULP below 2^23 = 8388607.5, still has fractional bit */
    emit_u(0xcaffffffu);         /* -(one ULP below 2^23) */
    emit_u(0x4b7fffffu);         /* 2^24 - 1 ULP = 16777215.0: all mantissa bits used */
    emit_u(0xcb7fffffu);         /* -(2^24 - 1 ULP) */
    emit_u(0x4b800000u);         /* 2^24 = 16777216.0 */
    emit_u(0xcb800000u);         /* -2^24 */
    emit(1.0e20f);               /* huge: floor is identity */
    emit(-1.0e20f);

    /* --- Section 10: ULP neighbors of exact integers in [2, 16] (13) --- */
    /* One ULP below and one ULP above small exact integers */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 (= 1.9999...) */
    emit_u(0x40000001u);  /* one ULP above 2.0 (= 2.0000...) */
    emit_u(0x404fffffu);  /* one ULP below 3.0 */
    emit_u(0x40500001u);  /* one ULP above 3.0 */
    emit_u(0x407fffffu);  /* one ULP below 4.0 */
    emit_u(0x40800001u);  /* one ULP above 4.0 */
    emit_u(0x40a7ffffu);  /* one ULP below 5.0 */
    emit_u(0x40a00001u);  /* one ULP above 5.0 - note: 5.0 = 0x40a00000 */
    emit_u(0x40bfffffu);  /* one ULP below 6.0 - 6.0 = 0x40c00000 */
    emit_u(0x40c00001u);  /* one ULP above 6.0 */
    emit_u(0x40dfffffu);  /* one ULP below 7.0 - 7.0 = 0x40e00000 */
    emit_u(0x40e00001u);  /* one ULP above 7.0 */
    emit_u(0x410fffffu);  /* one ULP below 9.0 - 9.0 = 0x41100000 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 10] in 200 steps */
static void test_sweep(void)
{
    float hi = 10.0f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, 1] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f800000u; /* 1.0 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
